from django.shortcuts import render, redirect
from my_music.music.forms import ProfileCreateForm, AlbumCreateForm
from my_music.music.models import Profile


def get_profile():
    try:
        profile = Profile.objects.get()
        return profile
    except Profile.DoesNotExist:
        return None

def index(request):
    profile = get_profile()
    if profile is None:
        return redirect('add profile')

    context = {
        'profile': profile,
    }

    return render(request, 'core/home-with-profile.html', context)


def add_album(request):
    form = AlbumCreateForm(request.POST or None, request.FILES or None)
    if form.is_valid():
        album = form.save(commit=False)
        album.user = request.user
        album.save()
    context = {
        'form': form,
    }
    return render(request, 'album/add-album.html', context)


def details_album(request, pk):

    return render(request, 'album/album-details.html')


def edit_album(request, pk):
    return render(request, 'album/edit-album.html')


def delete_album(request, pk):
    return render(request, 'album/delete-album.html')


def add_profile(request):
    form = ProfileCreateForm(request.POST or None, request.FILES or None)
    if form.is_valid():
        profile = form.save(commit=False)
        profile.user = request.user
        profile.save()

    context = {
        'form': form,
    }
    return render(request, 'core/home-no-profile.html', context)



def details_profile(request):
    return render(request, 'profile/profile-details.html')


def delete_profile(request):
    return render(request, 'profile/profile-delete.html')

